proof_block:
// The postcondition is an implication of the form
//   (premises_r1 && premises_r2) ==> det_..._equal(r1, r2, post1_self_@, post2_self_@)
// so the antecedent's conjuncts are NOT facts in the outer body — they are only
// available inside an `if` guarded by the same conjunctive premise.  The previous
// attempt asserted them at the top level (outside any guard) which is why they
// failed.  Pull both ensures-conjuncts in under one `if`, then reveal every
// opaque spec mentioned by `host_state_common_postconditions` / `receive_packet`
// so z3 can see the structural equalities they pin down.
reveal(HostState::host_state_common_postconditions);
reveal(HostState::valid);
reveal(HostState::abstractable);
reveal(Constants::valid);
reveal(Constants::abstractable);

let (sp1, ack1_g) = r1;
let (sp2, ack2_g) = r2;
let out1: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@);
let out2: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@);
let ack1: Packet = ack1_g@@;
let ack2: Packet = ack2_g@@;

if outbound_packet_seq_is_valid(sp1@)
    && receive_packet(pre_self_@, post1_self_@, cpacket@, out1, ack1)
    && post1_self_.host_state_common_postconditions(pre_self_, cpacket, sp1@)
    && outbound_packet_seq_is_valid(sp2@)
    && receive_packet(pre_self_@, post2_self_@, cpacket@, out2, ack2)
    && post2_self_.host_state_common_postconditions(pre_self_, cpacket, sp2@)
{
    // All six conjuncts of the antecedent are now in scope as facts.
    // Re-state the abstraction-set equality from host_state_common_postconditions
    // so z3 sees it for both runs (it lives behind a reveal).
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@) =~=
        extract_packets_from_lsht_packets(abstractify_outbound_packets_to_seq_of_lsht_packets(sp1@)));
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@) =~=
        extract_packets_from_lsht_packets(abstractify_outbound_packets_to_seq_of_lsht_packets(sp2@)));
}
